const file = $input.first().json;
const name = file.name || '';
const mime = file.mimeType || '';
const isVideo = mime.startsWith('video/') || /\.(mp4|mov|webm|mkv)$/i.test(name);
const isText = /\.(txt|md|srt)$/i.test(name);
if (!isVideo && !isText) throw new Error('Unsupported file type: ' + name);
const parents = (file.parents || []).map(p => (p.name || '').toLowerCase());
const folderPath = parents.join('/').toLowerCase();
let contentType = 'technical-walkthrough';
if (folderPath.includes('case-study')) contentType = 'case-study';
else if (folderPath.includes('podcast')) contentType = 'podcast';
const baseName = name.replace(/\.[^.]+$/, '');
const parts = baseName.split('_').map(p => p.trim());
let speakerName = '', company = '', title = baseName;
if (parts.length >= 3) { speakerName = parts[0]; company = parts[1]; title = parts.slice(2).join(' '); }
else if (parts.length === 2) { speakerName = parts[0]; title = parts[1]; }
return [{ json: { fileId: file.id, fileName: name, isVideo, isText, contentType, speakerName, company, title, mimeType: mime } }];

const w = $input.first().json;
const meta = $('Detect File Type + Content Type').first().json;
let transcript = '';
if (w.segments && w.segments.length) {
  transcript = w.segments.map(s => {
    const m = Math.floor(s.start / 60);
    const sec = Math.floor(s.start % 60);
    return `[${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}] ${s.text.trim()}`;
  }).join('\n');
} else { transcript = w.text || ''; }
return [{ json: { contentType: meta.contentType, transcript, speakerName: meta.speakerName, company: meta.company, title: meta.title, fileId: meta.fileId, fileName: meta.fileName } }];

const item = $input.first();
const meta = $('Detect File Type + Content Type').first().json;
let transcript = '';
if (item.binary && item.binary.data) {
  transcript = Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
} else if (item.json && item.json.data) {
  transcript = item.json.data;
}
if (!transcript || transcript.trim().length < 20) throw new Error('Transcript too short');
return [{ json: { contentType: meta.contentType, transcript, speakerName: meta.speakerName, company: meta.company, title: meta.title, fileId: meta.fileId, fileName: meta.fileName } }];

const input = $input.first().json;
const contentType = input.contentType || 'technical-walkthrough';
const FLOWS = {
  'technical-walkthrough': '5 scenes: Hook(big-stat-reveal) -> Speaker(person-scorecard) -> HowItWorks(workflow-pipeline) -> Results(data-table/kpi-dashboard) -> Arch+CTA(node-graph+cta-comment)',
  'case-study': '6 scenes: HookStat(big-stat-reveal) -> ClientIntro(person-scorecard) -> Challenge(comparison-split) -> Solution(timeline-steps) -> Results(kpi-dashboard) -> Trust+CTA(logo-endorsement+cta-comment)',
  'podcast': '4-6 scenes: GuestIntro(person-scorecard) -> KeyStat(big-stat-reveal) -> TopicViz(varies) -> CTA(cta-comment)'
};
const systemPrompt = 'B-roll scene generator for CUTAWAY format. Output JSON: { "meta": { "contentType": "' + contentType + '", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "" }, "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...}, "backgroundVideo": { "query": "..." } }], "textStrip": { "labels": [...] }, "lowerThirds": [...] }

Flow: ' + (FLOWS[contentType] || FLOWS['technical-walkthrough']) + '

ASSET HINTS: workflow-pipeline & node-graph nodes can have icon: "mdi:database" (Iconify). logo-endorsement: just set name (Brandfetch fills imageUrl). backgroundVideo: { query: "data center" } (Pexels fills url).

DIAGNOSTIC: durationInFrames 180-360 (6-12s). Adjacent scenes overlap 16+ frames. Percentages>95 need tickRange. No empty comparison-split sides.

Types: big-stat-reveal({value,prefix?,suffix?,color,subtitle}), person-scorecard({name,title,badges[{value,label}]}), kpi-dashboard({header,cards[{label,value,color,tickRange?}]}), workflow-pipeline({header,rows[[{label,sub?,glow?,icon?}]]}), data-table({header,table:{columns,rows}}), node-graph({header,nodes[{label,x,y,color,icon?}],edges[{from,to}]}), timeline-steps({header,steps[{label,status}]}), comparison-split({left:{header,color,icon,items},right:{header,color,icon,items}}), logo-endorsement({header,logos[{name,imageUrl?}]}), cta-comment({action,keyword})

frame=sec*30. Colors: #00D4FF #00FF88 #FF4444 #FF8C00 #8B5CF6. Output ONLY JSON.';
const context = [input.speakerName ? 'Speaker: ' + input.speakerName : '', input.company ? 'Company: ' + input.company : ''].filter(Boolean).join('
');
const userMessage = (context ? context + '

' : '') + 'Transcript:
' + input.transcript;
return [{ json: { ...input, systemPrompt, userMessage } }];

const prev = $('Build Claude Prompt').first().json;
const response = $input.first().json;
const content = (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) || '';
let config;
try { config = JSON.parse(content); }
catch (e) {
  const m = content.match(/\{[\s\S]*\}/);
  if (m) config = JSON.parse(m[0]);
  else throw new Error('Failed to parse: ' + content.substring(0, 300));
}
const totalFrames = config.scenes.reduce((max, s) => Math.max(max, s.from + s.durationInFrames), 0);
if (!config.meta || !config.scenes || !config.scenes.length) throw new Error('Invalid config');
return [{ json: { config, totalFrames, totalSeconds: (totalFrames / 30).toFixed(1), sceneCount: config.scenes.length, sceneTypes: config.scenes.map(s => s.type), title: prev.title, contentType: prev.contentType, sourceFileId: prev.fileId, sourceFileName: prev.fileName, generatedAt: new Date().toISOString() } }];

const item = $input.first().json;
const config = item.config;
const KEY = $vars.BRANDFETCH_API_KEY;
if (!KEY) return [{ json: item }];
for (const scene of config.scenes) {
  if (scene.type !== 'logo-endorsement') continue;
  for (const logo of scene.data.logos) {
    if (logo.imageUrl || !logo.name) continue;
    try {
      const r = await fetch('https://api.brandfetch.io/v2/brands/' + encodeURIComponent(logo.name), { headers: { 'Authorization': 'Bearer ' + KEY } });
      if (!r.ok) continue;
      const data = await r.json();
      const icon = (data.logos || []).find(l => l.type === 'icon') || (data.logos || [])[0];
      const fmt = icon && ((icon.formats || []).find(f => f.format === 'svg') || (icon.formats || []).find(f => f.format === 'png') || (icon.formats || [])[0]);
      if (fmt && fmt.src) logo.imageUrl = fmt.src;
    } catch (e) {}
  }
}
return [{ json: { ...item, config } }];

const item = $input.first().json;
const config = item.config;
const PEXELS = $vars.PEXELS_API_KEY;
const PIXABAY = $vars.PIXABAY_API_KEY;
async function pexels(q) { if (!PEXELS) return null; try { const r = await fetch('https://api.pexels.com/videos/search?query=' + encodeURIComponent(q) + '&per_page=3&orientation=landscape', { headers: { 'Authorization': PEXELS } }); if (!r.ok) return null; const d = await r.json(); const v = (d.videos || [])[0]; const f = v && ((v.video_files || []).find(f => f.quality === 'hd' && f.width >= 1280) || (v.video_files || [])[0]); return f ? f.link : null; } catch (e) { return null; } }
async function pixabay(q) { if (!PIXABAY) return null; try { const r = await fetch('https://pixabay.com/api/videos/?key=' + PIXABAY + '&q=' + encodeURIComponent(q) + '&per_page=3'); if (!r.ok) return null; const d = await r.json(); const v = (d.hits || [])[0]; return v && v.videos && (v.videos.medium && v.videos.medium.url || v.videos.small && v.videos.small.url) || null; } catch (e) { return null; } }
for (const scene of config.scenes) {
  if (!scene.backgroundVideo || !scene.backgroundVideo.query || scene.backgroundVideo.url) continue;
  const q = scene.backgroundVideo.query;
  let url = await pexels(q);
  if (!url) url = await pixabay(q);
  if (url) { scene.backgroundVideo.url = url; scene.backgroundVideo.source = url.includes('pexels') ? 'pexels' : 'pixabay'; }
}
return [{ json: { ...item, config } }];

const renderResp = $input.first().json;
const renderId = renderResp.renderId;
const statusUrl = $vars.RENDER_API_URL + '/status/' + renderId;
const downloadUrl = $vars.RENDER_API_URL + '/download/' + renderId;
const apiKey = $vars.RENDER_API_KEY;
const maxWaitMs = 900000;
const pollIntervalMs = 15000;
const start = Date.now();
while (Date.now() - start < maxWaitMs) {
  await new Promise(r => setTimeout(r, pollIntervalMs));
  try {
    const r = await fetch(statusUrl, { headers: { 'Authorization': 'Bearer ' + apiKey } });
    if (!r.ok) continue;
    const status = await r.json();
    if (status.status === 'complete') {
      return [{ json: { renderId, status: 'complete', downloadUrl, fileSizeMB: status.fileSizeMB } }];
    }
    if (status.status === 'error') throw new Error('Render failed: ' + (status.error || 'unknown'));
  } catch (e) {
    if (e.message && e.message.indexOf('Render failed') === 0) throw e;
  }
}
throw new Error('Render timeout after 15 minutes');
